import { useEffect, useState } from "react";
import { api } from "./api";

export function usePlans() {
    const [plans, setPlans] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    useEffect(() => {
        const fetchPlans = async () => {
            try {
                setLoading(true);

                const response = await api.get("/plans");

                const data = response.data;

                if (Array.isArray(data)) {
                    setPlans(data);
                }
                else if (Array.isArray(data.plans)) {
                    setPlans(data.plans);
                }
                else if (Array.isArray(data.data)) {
                    setPlans(data.data);
                }
                else {
                    setPlans([]);
                }
            } catch (err) {
                console.error("Failed to fetch plans:", err);
                setError(err.message);

                // Temporary fallback plans
                // Backend connect hone tak UI blank nahi hogi
                setPlans([
                    {
                        id: 1,
                        name: "Starter",
                        price: 79,
                        credits: 79,
                        description: "Basic market signals access",
                    },
                    {
                        id: 2,
                        name: "growth",
                        price: 149,
                        credits: 149,
                        description: "Advanced stock signals",
                    },
                    {
                        id: 3,
                        name: "premium",
                        price: 199,
                        credits: 199,
                        description: "Growth stock signals",
                    },
                    {
                        id: 3,
                        name: "Ultimate",
                        price: 299,
                        credits: 299,
                        description: "Premium AI trading signals",
                    },
                ]);
            } finally {
                setLoading(false);
            }
        };

        fetchPlans();
    }, []);

    return {
        plans,
        loading,
        error,
    };
}
